-- Automated Seed: User accounts

-- Map roles dynamically based on personnel positions
SELECT u.personnel_id, 
       CASE p.position_id
            WHEN 1 THEN 3 -- Airport Rescue & Fire Fighting Manager -> Manager
            WHEN 2 THEN 2 -- Vice President -> Vice President
            WHEN 3 THEN 4 -- RFF Performance Standard Team Leader -> RFF Performance Standard Team Leader
            WHEN 4 THEN 5 -- RFF OperationTeam Leader -> RFF OperationTeam Leader
            WHEN 5 THEN 6 -- RFF Maintenance Team Leader -> RFF Maintenance Team Leader
            WHEN 6 THEN 8 -- Rescue and Fire Fighting Squad Leader -> Squad Leader
            WHEN 7 THEN 9 -- Rescue Officer -> Officer
            WHEN 8 THEN 1 -- Admin -> Superuser
            ELSE 9
       END
FROM users u
JOIN personnels p ON u.personnel_id = p.id
ON CONFLICT DO NOTHING;
